%[text] # Interesting 2D Graphs
%[text:tableOfContents]{"heading":"Table of Contents"}
%[text] 
%%
%[text] ## Patch
%[text] [https://kr.mathworks.com/help/matlab/ref/patch.html](https://kr.mathworks.com/help/matlab/ref/patch.html)
%[text] 색깔로 채운 영역을 나타내는 그래프
%[text] ### 간단한 도형 영역
% 정사각형 영역
C = [0 0; 1 0; 1 1; 0 1]; %사각형을 위해 점 4개면 된다 / plot은 점 5개
% Define the vertices and corresponding colors for the patch
x = C(:, 1);
y = C(:, 2);
color = [0.5 0.5 0.5]; % Gray color
% Create the patch using the defined vertices and color
patch(x, y, color); %[output:9f10c951]
axis equal; % Set equal scaling for both axes %[output:9f10c951]
xlabel('X-axis'); %[output:9f10c951]
ylabel('Y-axis'); %[output:9f10c951]
title('2D Patch Example'); %[output:9f10c951]
%%
clf(figure(2)) %[output:898f6667]
figure(2);
c = [1,0; 2,0; 0,2; 0,1];
xm = [0 0 2 2];
ym = [0 -2 0 -2];
x = c(:, 1);
y = c(:, 2);

c = [0.5 0.5 0];

X = x+xm;
Y = y+ym;

patch(X, Y, c); %[output:898f6667]
axis([-2 4 -1 3]); grid on; %[output:898f6667]
axis equal; %[output:898f6667]
%%
%[text] ### 랜덤 위치에 랜덤 크기로 나타내기
figure; %[output:32d36684]
clear;

C = [-1,1; 1,1; 0, 2];
x = C(:,1);
y = C(:, 2);
n  = 100; % number of squares
s  = randi([5 10], 1, n); % 크기
c = randi(20, 1, n); %color
cx = 5*rand(1,n); % 위치
cy = 5*rand(1,n); % 위치
X  = x + cx; % 원하는 위치로 이동시킨 n개의 정사각형들의 x-좌표
Y  = y + cy; % 원하는 위치로 이동시킨 n개의 정사각형들의 y-좌표
Xs = X .* s; % 각 정사각형에 크기 설정하기
Ys = Y .* s; % 똑 같은 비율로 세로에도 적용
h = patch(Xs, Ys, c, "FaceAlpha", 0.1); %색상 cx에따라 달라진다 %[output:32d36684]
h.EdgeColor = 'none'; %[output:32d36684]
%patch에 스칼라 벡터(s)를 색으로 넘기면 MATLAB은 그 값들을 색 인덱스(CData)로 해석하여 
%현재 플롯의 colormap(예: parula, jet 등)에 매핑 / 
%면 투명도로, 범위 [0,1] 사이의 스칼라로 지정됩니다. 값이 1이면 불투명하고, 값이 0이면 완전히 투명합니다. 
%값이 0과 1 사이이면 반투명합니다.
axis equal;   axis off; % 도 시도해 보세요. %[output:32d36684]
%axis off;
%%
%[text] ## Bubble Chart
%[text] [https://kr.mathworks.com/help/matlab/ref/bubblechart.html](https://kr.mathworks.com/help/matlab/ref/bubblechart.html)
%[text] (x, y) 위치에 크기 sz인 버블로 영역을 나타내는 그래프
n  = 100;         % 버블의 갯수
x  = 1:n;        % 버블의 x-좌표 1~20까지 순서대로
y  = rand(1,n); % 버블의 y-좌표 0~1까지 20개의 무작위 실수
sz = rand(1,n); % 크기 
c  = randperm(n); % 색상 인덱스 permutation
%1에서 20까지의 정수(반복되는 요소 없음)로 구성된 난수 순열을 생성합니다.
bubblechart(x, y, sz, c); %Marker로 만든다. colormap %[output:1c376400]
axis off; %[output:1c376400]
% c색상이 포함된 원형 마커 (버블)을 x값, y값에 size를 맞춰서 보여줍니다
%%
%[text] ## Geobubble - 지도 위에 그리는 버블 차트
%[text] [https://kr.mathworks.com/help/matlab/ref/geobubble.html](https://kr.mathworks.com/help/matlab/ref/geobubble.html)
%[text] 생성형 AI Prompt:
%[text] `"Matlab에서 대한민국 남한의 광역시와 도의 인구를 geobubble() 함수로 그리려고 합니다. 2025년 말 기준 인구 데이터를 이용하여 MATLAB geobubble() 차트로 그리기 위한 코드를 제시해 주세요."`
%% South Korea regional population geobubble (year-end 2025)
% Source: KOSIS e-지방지표 / 행정안전부 주민등록인구현황
% Units: persons

clear; clc;

Region = [ ...
    "서울특별시"
    "부산광역시"
    "대구광역시"
    "인천광역시"
    "광주광역시"
    "대전광역시"
    "울산광역시"
    "세종특별자치시"
    "경기도"
    "강원특별자치도"
    "충청북도"
    "충청남도"
    "전북특별자치도"
    "전라남도"
    "경상북도"
    "경상남도"
    "제주특별자치도"
    ];
Region = categorical(Region); % 입력 배열로부터 categorical형 배열을 만듭니다. 출력 배열의 범주는 입력 배열의 정렬된 고유한 값들입니다.
% categorical은 High, Med, Low와 같은 유한한 이산 범주 집합에 값을 할당하는 데이터형
% 이러한 범주에는 High > Med > Low와 같은 수학적 정렬을 적용할 수 있다.

% Representative coordinates (near city/provincial hall)
Lat = [ ...
    37.5665
    35.1796
    35.8714
    37.4563
    35.1595
    36.3504
    35.5384
    36.4800
    37.2750
    37.8228
    36.6357
    36.6588
    35.8200
    34.8161
    36.5760
    35.2383
    33.4996
    ];

Lon = [ ...
    126.9780
    129.0756
    128.6014
    126.7052
    126.8526
    127.3845
    129.3114
    127.2890
    127.0094
    128.1555
    127.4914
    126.6728
    127.1088
    126.4630
    128.5056
    128.6924
    126.5312
    ];

Population = [ ...
     9299548
     3241600
     2353032
     3051961
     1392013
     1440729
     1091948
      391965
    13730135
     1508500
     1596502
     2136753
     1724856
     1779135
     2506526
     3207383
      664792
    ];
T = table(Region, Lat, Lon, Population) %[output:2d9ee250]
% 변수 var1,...,varN에서 테이블을 만듭니다. 변수는 크기와 데이터형이 서로 다를 수 있지만, 모든 변수는 행 개수가 동일헤야 함
figure("Position",[0 0 600 600]); %[output:1a189db4]
% Figure를 주 디스플레이의 오른쪽으로 0픽셀, 
% 왼쪽 하단 코너에서 0픽셀 
% 너비가 500픽셀, 높이가 300픽셀이 되도록 크기를 지정합니다.

gb = geobubble(T, 'Lat', 'Lon', ... %[output:1a189db4]
    'SizeVariable',  'Population', ... %[output:1a189db4]
    'ColorVariable', 'Region'); %[output:1a189db4]
%Lat(위도) Lon(경도)에 버블 그린다. SizeVariable은 population 벡터(double)에 맞춰서, ColorVariable은 Region(categoricl)에 맞춰서 
%SizeVariable속성을 설정하면 MATLAB은 SizeData 속성을 업데이트
%소스 테이블의 요소를 참조하는 변수 인덱스로 지정됩니다.

geobasemap bluegreen % bluegreen streets streets-light %[output:1a189db4]
legend %[output:1a189db4]
title('대한민국 시도별 주민등록인구 (2025년 연말 기준)'); %[output:1a189db4]
gb = gca %[output:9f82a383]
gb.SizeLegendTitle  = 'Population'; %[output:1a189db4]
gb.ColorLegendTitle = 'Region'; %[output:1a189db4]
gb.BubbleWidthRange = [8 50]; % 최소 거품 지름과 최대 거품 지름 %[output:1a189db4]
geolimits([33 39], [124 132]); %geolimits(latlim,lonlim) geobasemap 경도의 범위/위도의 범위 %[output:1a189db4]
%%
%인천대와 위치 버블
Lat = []
%%
%[text] %[text:anchor:H_A401434E] ## Pie Charts
%[text] %[text:anchor:H_EFF5A079] ### Data and Names
%[text] ref: [piechart](https://kr.mathworks.com/help/matlab/ref/piechart.html)
grades = [15 43 92 80 96]; % 각 과목의 점수
names  = ["English", ... %14점 - 영어 / 43점 - 수학 / 92점 - 과학 / 80점 - 미술 / 96점 - 지리학
    "Math", "Science", ...
    "Art", "Geography"];
h = piechart(grades, names); %[output:0ffc422a]
%piechart(data,names) specifies names for the slices.
title("Midterm Scores") %[output:0ffc422a]
%%
%[text] %[text:anchor:H_D1E5E043] ### Further Investigation
%[text] %[text:anchor:H_179F9085] #### Direction
h.Direction = "counterclockwise"; %[control:dropdown:0781]{"position":[15,33]} %[output:52c3157b]
%[text] %[text:anchor:H_1529DD88] #### Labels
h.LabelStyle = "namepercent"; %[control:dropdown:7d8c]{"position":[16,29]} %[output:52c3157b]
%[text] %[text:anchor:H_B367520E] #### Color Order
colororder("gem"); %[output:52c3157b]
%[text] %[text:anchor:H_5AE290F3] #### Explode Wedges
%h.ExplodedWedges = 2;
%[text] %[text:anchor:H_D4D4869C] #### Others
%h.EdgeColor = "none";
%h.StartAngle = 55;
%%
%[text] %[text:anchor:H_C241B398] ## Donut Charts
%[text] %[text:anchor:H_108D2015] ### Data and Names
%[text] ref: [donut chart](https://kr.mathworks.com/help/matlab/ref/donutchart.html)
grades = [15 43 92 80 96];
names  = ["English", "Math", "Science", ...
    "Geography", "Art"];
h = donutchart(grades, names); %[output:3aa444fa]
title("Midterm Scores") %[output:3aa444fa]
h = gca %[output:5f3f85bc]
%%
%[text] %[text:anchor:H_CD57533C] ### Further Investigation
%[text] %[text:anchor:H_9B8BB0B2] #### Direction
h.Direction = "counterclockwise"; %[control:dropdown:02fa]{"position":[15,33]} %[output:25e0ee98]
%[text] %[text:anchor:H_D5F33E61] #### Labels
h.LabelStyle = "namedata"; %[control:dropdown:5f05]{"position":[16,26]} %[output:25e0ee98]
%[text] %[text:anchor:H_1B97897D] #### Color Order
colororder("meadow"); %[output:25e0ee98]
%[text] %[text:anchor:H_6B45CD91] #### Explode Wedges
h.ExplodedWedges = 5; %h의 2번째 인덱스 항목을 돌출시키세요 %[output:25e0ee98]
%[text] %[text:anchor:H_01D2D27E] #### Others
%h.EdgeColor = "none";
h.StartAngle = 90; %[output:25e0ee98]
h.CenterLabel = {"성적", "Scores"}; %[output:25e0ee98]
%%
%[text] ## Area Graph
%[text] [https://kr.mathworks.com/help/matlab/ref/area.html](https://kr.mathworks.com/help/matlab/ref/area.html)
n = 5; % number of areas
x = linspace(0,10, 1000)'; %0부터 10까지 1000으로 나눈다 사이즈 1000x1
y = rand(1000,n) .* rand(1,n); %0~1의 난수 1000x5 .* 1x5;
t = cumsum(y)*0.05*pi + rand(1,n)*2*pi; %1000x5 + 1x5;
%B = cumsum(A)는 크기가 1이 아닌 A의 첫 번째 배열 차원의 시작에서부터 계산하여 A의 누적합을 반환합니다.
%A가 행렬이면 B는 A의 누적합을 포함하는 동일한 크기의 행렬입니다.
Y = cos(t) + */rand(1,n) + 1.5; %1000x5
area(x,Y); %[output:34cf6ed4]
%area(X,Y)는 Y의 값을 x 좌표 X에 대해 플로팅합니다. 그런 다음, 함수는 다음과 같이 Y의 형태를 따라 곡선 사이의 영역을 채웁니다.
%Y가 벡터이면 플롯은 하나의 곡선을 포함합니다. area는 곡선과 가로 축 사이의 영역을 채웁니다.
%Y가 행렬이면 플롯은 Y의 각 열에 대해 하나의 곡선을 포함합니다. area는 곡선들 사이의 영역을 채우고 이를 쌓아 올려, 각 x 좌표에서 각각의 행 요소가 전체 높이에서 차지하는 상대적 비중을 보여줍니다.
ax = gca; ax.Color = "g";  %[output:34cf6ed4]

%ax.XTick = []; ax.YTick = [];
%%
c = [-1, 1; 1, 3; 2,2; 3,3];
x = c(:,1);
y = c(:, 2);
color = [0.2 0.5 0.8];
h = area(x, y); %[output:8021cdf1]
h.FaceColor = color; %[output:8021cdf1]
axis([-5 5 -3 6]) %[output:8021cdf1]
%%
%동해바다
n = 5; % 5개의 층을 쌓겠다.
x = linspace(0,10, 1000)'; %0부터 10까지 1000으로 나눈다 사이즈 1000x1
y = ones(1000,n); %1로 이루어진 1000x5
t = cumsum(y)*0.005*pi + ones(1,n)*2*pi;%cumsum(y): [1; 2; ... 1000]' 형태의 1000x5 *0.05*pi 느슨한 파동 제공 
Y = cos(t) + 0.3*ones(1,n) + 8; %1000x5  y(높이)범위 e.g.) [-1, 1] -> [7.3, 9.3]
c = [0 0 1; 0.1 0.1 0.8; 0.4 0.4 0.7; 0.5 0.5 0.8; 0.8 0.8 1]';
h = area(x,Y); %[output:275617ed]

ax = gca;
h(1).FaceColor = c(:,1); h(2).FaceColor = c(:,2); h(3).FaceColor = c(:,3); h(4).FaceColor = c(:,4); h(5).FaceColor = c(:,5);  %[output:275617ed]
ax.Color = 'k'; %[output:275617ed]
ax.XTick = []; ax.YTick = []; %[output:275617ed]
%%
% 원래 구조를 유지한 부드러운 물결(색상만 파란색 그라데이션으로 변경)
n = 5; % number of areas
x = linspace(0,10,1000)';
y = rand(1000,n) .* rand(1,n);

% 원래 위상 계산
t_raw = cumsum(y)*0.05*pi + rand(1,n)*2*pi;

% 1) 위상 평활
winsize = 25;
t = smoothdata(t_raw, 1, "gaussian", winsize);

% 2) 코사인 적용 + 층별 상수 보정
Y_raw = cos(t) + rand(1,n) + 1.5;

% 3) 마지막으로 각 열을 약하게 스무스
Y = smoothdata(Y_raw, 1, "movmean", 9);

% 그리기 (원래와 동일)
figure('Color','w'); %[output:6560e056]
h = area(x, Y);    % h는 각 층에 대한 handle 배열 %[output:6560e056]
ax = gca;

% 파란색 그라데이션 생성 (위->아래: 연한->진한)
lightBlue = [0.65 0.9 1.0];
darkBlue  = [0.02 0.25 0.55];
colors = zeros(n,3);
for k = 1:n
    tt = (k-1)/(n-1);                       % 0..1
    colors(k,:) = (1-tt)*lightBlue + tt*darkBlue;
end

% 각 area 패치에 색 지정 (area는 앞->뒤 순서로 반환됨)
for k = 1:length(h)
    set(h(k), 'FaceColor', colors(k,:), 'EdgeColor', 'none', 'FaceAlpha', 0.95); %[output:6560e056]
end

% 기존 축 설정 유지
ax.Color = "g"; %[output:6560e056]
ax.XTick = []; %[output:6560e056]
ax.YTick = []; %[output:6560e056]
axis([0 10 min(Y(:))-0.2 max(Y(:))+0.2]); %[output:6560e056]
box off; %[output:6560e056]
%%
%[text] ## Digital Clock
%[text] [https://www.dafont.com/ds-digital.font](https://www.dafont.com/ds-digital.font)
%[text] 디지털 시계 폰트를 이용하여 현재 시간 나타내기
% 시계 프레임
C = [0 0; 4 0; 4 1; 0 1; 0 0];
x = C(:,1); y = C(:,2);
f = figure( 'Position', [100 100 400 150]);
set(f, 'Visible', 'on');
plot(x, y, 'b-', 'LineWidth', 4 );

% 현재 시간
h = text(0.3, 0.5, "12:34:10", 'FontName', 'DS-Digital', 'FontSize', 60);
h.HorizontalAlignment = 'left';
h.VerticalAlignment = 'middle';
axis off;
% update the current time every second
while isvalid(h)
    h.String = string(datetime,'hh:mm:ss');
    pause(1);
end
%%
%[text] ## Analog Clock
%[text] - 시침, 분침, 초침을 line으로 그린다.
%[text] - 매 초마다 시침, 분침, 초침의 각도를 새로 계산한다. \
% Create a figure
figure; %[output:302351e4]
hold on; %[output:302351e4]
axis equal; %[output:302351e4]
xlim([-1.5, 1.5]); %[output:302351e4]
ylim([-1.5, 1.5]); %[output:302351e4]
set(gca, 'visible', 'off'); %[output:302351e4]

% Draw the clock face
th = linspace(0, 2*pi, 100);
x  = cos(th);
y  = sin(th);
patch(x, y, 'y', 'FaceAlpha', 0.5); %[output:302351e4]
plot(x, y, 'k');  % Draw the outer circle %[output:302351e4]
for i = 1:12
    % Calculate tick positions
    x = 0.9 * cos(-pi/6 * i + pi/2);
    y = 0.9 * sin(-pi/6 * i + pi/2);
    text(x, y, num2str(i), 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle'); %[output:302351e4]
end

% Initialize clock hands
hHand = line([0 0], [0 0.5 ], 'LineWidth', 7, 'Color', 'k'); %[output:302351e4]
mHand = line([0 0], [0 0.75], 'LineWidth', 5, 'Color', 'k'); %[output:302351e4]
sHand = line([0 0], [0 0.9 ], 'LineWidth', 2, 'Color', 'r'); %[output:302351e4]

while ishandle(hHand) %[output:group:4cc827ea]
    % Get current time
    t = datetime('now', 'Format', 'HH:mm:ss');
    hour   = t.Hour;
    minute = t.Minute;
    second = t.Second;

    % Update hour hand
    hAngle = 2*pi*(hour/12 + minute/720);
    set(hHand, 'XData', [0 0.5*sin(hAngle)], 'YData', [0 0.5*cos(hAngle)]); %[output:302351e4]

    % Update minute hand
    mAngle = 2*pi*minute/60;
    set(mHand, 'XData', [0 0.75*sin(mAngle)], 'YData', [0 0.75*cos(mAngle)]);

    % Update second hand
    sAngle = 2*pi*second/60;
    set(sHand, 'XData', [0 0.9*sin(sAngle)], 'YData', [0 0.9*cos(sAngle)]);

    pause(1);  % Update every second
end %[output:group:4cc827ea]
%%
%가장 멋있는 시계

%[appendix]{"version":"1.0"}
%---
%[metadata:view]
%   data: {"layout":"inline"}
%---
%[control:dropdown:0781]
%   data: {"defaultValue":"\"clockwise\"","itemLabels":["\"clockwise\"","\"counterclockwise\""],"items":["\"clockwise\"","\"counterclockwise\""],"label":"Drop down","run":"Section"}
%---
